            check(reopened_sheet.cell_count() == 1,
                "styled erase_rows post-noop reopened output should keep remaining sparse count");
            const std::vector<fastxlsx::WorksheetCellSnapshot> cells =
                reopened_sheet.sparse_cells();
            check(cells.size() == 1,
                "styled erase_rows post-noop reopened sparse_cells should expose A3 only");
